from zeep import Client

# URL of the WSDL file provided by the insurance service
wsdl_url = 'http://example.com/insurance-service?wsdl'

# Create a client using the WSDL URL
client = Client(wsdl=wsdl_url)

def get_insurance_quote(policy_number, customer_name):
    # Construct the SOAP request body with user input
    soap_request = {
        'PolicyNumber': policy_number,
        'CustomerName': customer_name
    }
    
    # Send the SOAP request and receive the response
    response = client.service.LookupPolicy(**soap_request)
    
    return response

# Accept user input for policy lookup
policy_number = input("Enter policy number: ")
customer_name = input("Enter customer name: ")

# Get the insurance quote based on user input
quote = get_insurance_quote(policy_number, customer_name)

# Print the response from the insurance service
print("Insurance Quote Response:")
print(quote)